import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"灵性","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/5.能量池/灵性.md","filePath":"4.资源分区/5.能量池/灵性.md"}'),p={name:"4.资源分区/5.能量池/灵性.md"};function d(l,a,i,_,b,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"灵性",tabindex:"-1"},[s("灵性 "),e("a",{class:"header-anchor",href:"#灵性","aria-label":'Permalink to "灵性"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"汹涌疾风021")])])],-1),o('<h1 id="灵性-1" tabindex="-1">灵性 <a class="header-anchor" href="#灵性-1" aria-label="Permalink to &quot;灵性&quot;">​</a></h1><p>灵性</p><p>西方通用能量<br> 灵性代表着一个有心智的生物所具有的神秘学精神体，是生物最根本的精髓。除精神体之外，一个生物还具有星灵体、心智体、以太体。<br> 星灵体是生物沟通灵界、星空的途径，也是占卜、释放魔法的媒介。<br> 心智体负责与肉体结合、牵涉推理、思考、洞察等方面，是生物对事物认识能力的综合体现。<br> 以太体在最外层，是生命能量和肉体状态的表现，外向显征为气场。</p><p>灵性的关键属性：沉着+感知/智力/风度<br> 具体的关键属性由开启灵性能量池的能力决定<br> 沉着象征着最根本的精神体<br> 感知象征着沟通外界的星灵体<br> 智力象征着综合认知的心智体<br> 风度象征着外向气场的以太体</p><p>特殊的，当你承受精神束缚异常点数时，你的灵性能量池会减少等同精神束缚异常点数的上限，直到这些异常点数被移除。</p><p>灵性的恢复方式<br> 1、每次长休息后，灵性会恢复至满值。<br> 2、每进行一次短休息，进行一次关键属性检定，恢复成功数点灵性。</p><p>灵性的基础使用方式：<br> 在进行灵性关键属性检定时，支付1点灵性以获得1点对应属性的内在加值。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',9)])])}const m=r(p,[["render",d]]);export{f as __pageData,m as default};
